/**
 * Integration tests for the full notification pipeline.
 *
 * Tests the end-to-end flow:
 *   Domain Event → EventBus → NotificationService → Preferences Check → Adapter Dispatch → History Log
 *
 * Unlike unit tests that test components in isolation, these tests wire up the
 * full stack: EventBus, NotificationService, all three adapters (email, SMS,
 * webhook), PreferencesService (with real repository + database), and
 * NotificationHistoryService (with real repository + database).
 */

import { describe, it, expect, beforeEach } from 'vitest';

// Events
import { EventBus } from '../../src/events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

// Services
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { PreferencesService, resetPreferencesIdCounter } from '../../src/services/preferences.service.js';
import {
  NotificationHistoryService,
  resetNotificationLogIdCounter,
} from '../../src/services/notification-history.service.js';

// Adapters
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';

// Repositories
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';

// Data layer
import { Database } from '../../src/utils/database.js';

// Models
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';

// ---------------------------------------------------------------------------
// Test helpers
// ---------------------------------------------------------------------------

function makeUser(overrides?: Partial<User>): User {
  return {
    id: 'user-1',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

function makeOrder(overrides?: Partial<Order>): Order {
  return {
    id: 'order-1',
    userId: 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
    total: 20,
    status: 'pending',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

function makeOrderCreatedEvent(user?: User, order?: Order): OrderCreatedEvent {
  const u = user ?? makeUser();
  const o = order ?? makeOrder({ userId: u.id });
  return { type: 'order:created', order: o, user: u, timestamp: new Date() };
}

function makeStatusChangedEvent(
  order?: Order,
  previousStatus = 'pending',
  newStatus = 'confirmed',
): OrderStatusChangedEvent {
  const o = order ?? makeOrder({ status: newStatus as Order['status'] });
  return { type: 'order:status-changed', order: o, previousStatus, newStatus, timestamp: new Date() };
}

// ---------------------------------------------------------------------------
// Full pipeline wiring
// ---------------------------------------------------------------------------

interface Pipeline {
  db: Database;
  eventBus: EventBus;
  notificationService: NotificationService;
  preferencesService: PreferencesService;
  historyService: NotificationHistoryService;
  emailAdapter: EmailAdapter;
  smsAdapter: SmsAdapter;
  webhookAdapter: WebhookAdapter;
}

function createPipeline(): Pipeline {
  const db = new Database();
  const eventBus = new EventBus();

  // Repositories
  const preferencesRepo = new PreferencesRepository(db);
  const notificationLogRepo = new NotificationLogRepository(db);

  // Services
  const preferencesService = new PreferencesService(preferencesRepo);
  const historyService = new NotificationHistoryService(notificationLogRepo);
  const notificationService = new NotificationService(eventBus);

  // Adapters
  const emailAdapter = new EmailAdapter();
  const smsAdapter = new SmsAdapter();
  const webhookAdapter = new WebhookAdapter({ url: 'https://hooks.example.com/notify' });

  // Wire up
  notificationService.setPreferencesService(preferencesService);
  notificationService.setHistoryService(historyService);
  notificationService.registerAdapter(emailAdapter);
  notificationService.registerAdapter(smsAdapter);
  notificationService.registerAdapter(webhookAdapter);

  return {
    db,
    eventBus,
    notificationService,
    preferencesService,
    historyService,
    emailAdapter,
    smsAdapter,
    webhookAdapter,
  };
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe('Notification Pipeline Integration', () => {
  let pipeline: Pipeline;

  beforeEach(() => {
    resetNotificationIdCounter();
    resetPreferencesIdCounter();
    resetNotificationLogIdCounter();
    pipeline = createPipeline();
  });

  // =========================================================================
  // 1. Email channel — end-to-end
  // =========================================================================
  describe('email channel end-to-end', () => {
    it('should deliver email notification when email preferences are enabled', async () => {
      const { eventBus, emailAdapter, notificationService, historyService, preferencesService } = pipeline;

      const user = makeUser({ id: 'user-1', email: 'alice@example.com' });
      // Ensure email is enabled (default)
      preferencesService.getOrCreatePreferences(user.id);

      await eventBus.emit(makeOrderCreatedEvent(user));

      // Email adapter received the message
      const sent = emailAdapter.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]!.to).toBe('alice@example.com');
      expect(sent[0]!.subject).toContain('Order Confirmation');

      // Notification stored in service
      const emailNotifs = notificationService.getNotifications().filter((n) => n.channel === 'email');
      expect(emailNotifs).toHaveLength(1);
      expect(emailNotifs[0]!.status).toBe('sent');
      expect(emailNotifs[0]!.type).toBe('order_confirmation');

      // History log persisted
      const logs = historyService.query({ channel: 'email', status: 'sent' });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.recipient).toBe('alice@example.com');
      expect(logs[0]!.type).toBe('order_confirmation');
    });

    it('should render email template with order details', async () => {
      const { eventBus, emailAdapter, preferencesService } = pipeline;

      const user = makeUser({ id: 'user-1', email: 'bob@example.com' });
      preferencesService.getOrCreatePreferences(user.id);

      const order = makeOrder({
        id: 'order-42',
        userId: user.id,
        items: [
          { productId: 'p1', name: 'Laptop', quantity: 1, unitPrice: 999 },
          { productId: 'p2', name: 'Mouse', quantity: 2, unitPrice: 25 },
        ],
        total: 1049,
      });

      await eventBus.emit(makeOrderCreatedEvent(user, order));

      const sent = emailAdapter.getSentEmails();
      expect(sent).toHaveLength(1);
      // HTML body should contain order details
      expect(sent[0]!.html).toContain('Order Confirmation');
      expect(sent[0]!.body).toContain('Laptop x1');
      expect(sent[0]!.body).toContain('Mouse x2');
    });
  });

  // =========================================================================
  // 2. SMS channel — end-to-end
  // =========================================================================
  describe('SMS channel end-to-end', () => {
    it('should deliver SMS when SMS preferences are enabled and recipient is valid phone', async () => {
      const { eventBus, smsAdapter, notificationService, historyService, preferencesService } = pipeline;

      // For SMS to succeed, the recipient must be E.164.
      // order:status-changed uses order.userId as recipient, so we set userId to a phone number.
      const phoneUserId = '+14155551234';
      preferencesService.updatePreferences(phoneUserId, { sms: { enabled: true } });

      const order = makeOrder({ userId: phoneUserId, status: 'confirmed' });
      await eventBus.emit(makeStatusChangedEvent(order, 'pending', 'confirmed'));

      // SMS adapter received the message
      const sent = smsAdapter.getSentMessages();
      expect(sent).toHaveLength(1);
      expect(sent[0]!.to).toBe(phoneUserId);
      expect(sent[0]!.message).toContain('Order Update');

      // Notification stored with correct channel
      const smsNotifs = notificationService.getNotifications().filter((n) => n.channel === 'sms');
      expect(smsNotifs).toHaveLength(1);
      expect(smsNotifs[0]!.status).toBe('sent');

      // History log
      const logs = historyService.query({ channel: 'sms', status: 'sent' });
      expect(logs).toHaveLength(1);
    });

    it('should fail SMS gracefully when recipient is not a valid phone number', async () => {
      const { eventBus, smsAdapter, notificationService, historyService, preferencesService } = pipeline;

      // order:created uses user.email as recipient — not E.164
      const user = makeUser({ id: 'user-1', email: 'alice@example.com' });
      preferencesService.updatePreferences(user.id, { sms: { enabled: true } });

      await eventBus.emit(makeOrderCreatedEvent(user));

      // SMS adapter rejects non-phone recipient
      expect(smsAdapter.getSentMessages()).toHaveLength(0);

      // Notification recorded as failed
      const smsNotifs = notificationService.getNotifications().filter((n) => n.channel === 'sms');
      expect(smsNotifs).toHaveLength(1);
      expect(smsNotifs[0]!.status).toBe('failed');
      expect(smsNotifs[0]!.error).toContain('phone number');

      // Failed notifications are also logged in history
      const failedLogs = historyService.query({ channel: 'sms', status: 'failed' });
      expect(failedLogs).toHaveLength(1);
    });
  });

  // =========================================================================
  // 3. Webhook channel — end-to-end
  // =========================================================================
  describe('webhook channel end-to-end', () => {
    it('should deliver webhook notification when webhook preferences are enabled', async () => {
      const { eventBus, webhookAdapter, notificationService, historyService, preferencesService } = pipeline;

      const user = makeUser({ id: 'user-1', email: 'alice@example.com' });
      preferencesService.updatePreferences(user.id, { webhook: { enabled: true } });

      await eventBus.emit(makeOrderCreatedEvent(user));

      // Webhook adapter delivered
      const deliveries = webhookAdapter.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]!.url).toBe('https://hooks.example.com/notify');
      expect(deliveries[0]!.payload.type).toBe('order_confirmation');
      expect(deliveries[0]!.payload.recipient).toBe('alice@example.com');
      expect(deliveries[0]!.payload.metadata?.orderId).toBe('order-1');

      // Notification stored
      const webhookNotifs = notificationService.getNotifications().filter((n) => n.channel === 'webhook');
      expect(webhookNotifs).toHaveLength(1);
      expect(webhookNotifs[0]!.status).toBe('sent');

      // History log
      const logs = historyService.query({ channel: 'webhook', status: 'sent' });
      expect(logs).toHaveLength(1);
    });

    it('should include metadata in webhook payload', async () => {
      const { eventBus, webhookAdapter, preferencesService } = pipeline;

      const user = makeUser({ id: 'user-1' });
      preferencesService.updatePreferences(user.id, { webhook: { enabled: true } });

      const order = makeOrder({ id: 'order-99', userId: user.id });
      await eventBus.emit(makeOrderCreatedEvent(user, order));

      const deliveries = webhookAdapter.getDeliveries();
      expect(deliveries[0]!.payload.metadata).toEqual(
        expect.objectContaining({ orderId: 'order-99', userId: 'user-1' }),
      );
    });
  });

  // =========================================================================
  // 4. History logging across all channels
  // =========================================================================
  describe('notification history logging', () => {
    it('should log all notifications to history across multiple channels', async () => {
      const { eventBus, historyService, preferencesService } = pipeline;

      const user = makeUser({ id: 'user-1', email: 'alice@example.com' });
      // Enable email (default) and webhook
      preferencesService.updatePreferences(user.id, { webhook: { enabled: true } });

      await eventBus.emit(makeOrderCreatedEvent(user));

      // Email + SMS (failed) + Webhook = 3 notifications logged
      // Email: sent (valid email), SMS: failed (not a phone number), Webhook: sent
      const allLogs = historyService.query({});
      expect(allLogs.length).toBeGreaterThanOrEqual(2);

      const emailLogs = historyService.query({ channel: 'email' });
      expect(emailLogs).toHaveLength(1);
      expect(emailLogs[0]!.status).toBe('sent');

      const webhookLogs = historyService.query({ channel: 'webhook' });
      expect(webhookLogs).toHaveLength(1);
      expect(webhookLogs[0]!.status).toBe('sent');
    });

    it('should persist notification metadata in history', async () => {
      const { eventBus, historyService, preferencesService } = pipeline;

      const user = makeUser({ id: 'user-1', email: 'alice@example.com' });
      preferencesService.getOrCreatePreferences(user.id);

      const order = makeOrder({ id: 'order-77', userId: user.id });
      await eventBus.emit(makeOrderCreatedEvent(user, order));

      const logs = historyService.query({ channel: 'email' });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.metadata).toEqual(
        expect.objectContaining({ orderId: 'order-77', userId: 'user-1' }),
      );
    });

    it('should allow querying history by notification type', async () => {
      const { eventBus, historyService, preferencesService } = pipeline;

      const user = makeUser({ id: 'user-1', email: 'alice@example.com' });
      preferencesService.getOrCreatePreferences(user.id);

      // Emit order:created (→ order_confirmation) and order:status-changed (→ order_status_update)
      await eventBus.emit(makeOrderCreatedEvent(user));
      await eventBus.emit(makeStatusChangedEvent(makeOrder({ userId: user.id })));

      const confirmations = historyService.query({ type: 'order_confirmation' });
      expect(confirmations.length).toBeGreaterThanOrEqual(1);

      const statusUpdates = historyService.query({ type: 'order_status_update' });
      expect(statusUpdates.length).toBeGreaterThanOrEqual(1);
    });

    it('should track total count across multiple events', async () => {
      const { eventBus, historyService, preferencesService } = pipeline;

      const user = makeUser({ id: 'user-1', email: 'alice@example.com' });
      preferencesService.getOrCreatePreferences(user.id);

      expect(historyService.getCount()).toBe(0);

      await eventBus.emit(makeOrderCreatedEvent(user));
      const countAfterFirst = historyService.getCount();
      expect(countAfterFirst).toBeGreaterThan(0);

      await eventBus.emit(makeOrderCreatedEvent(user, makeOrder({ id: 'order-2', userId: user.id })));
      expect(historyService.getCount()).toBeGreaterThan(countAfterFirst);
    });
  });

  // =========================================================================
  // 5. User preferences — suppression
  // =========================================================================
  describe('user preferences enforcement', () => {
    it('should suppress email when user disables email globally', async () => {
      const { eventBus, emailAdapter, notificationService, preferencesService } = pipeline;

      const user = makeUser({ id: 'user-1', email: 'alice@example.com' });
      preferencesService.updatePreferences(user.id, { email: { enabled: false } });

      await eventBus.emit(makeOrderCreatedEvent(user));

      // Email adapter was NOT called
      expect(emailAdapter.getSentEmails()).toHaveLength(0);

      // No email notification record
      const emailNotifs = notificationService.getNotifications().filter((n) => n.channel === 'email');
      expect(emailNotifs).toHaveLength(0);
    });

    it('should suppress specific notification category while allowing others', async () => {
      const { eventBus, emailAdapter, notificationService, preferencesService } = pipeline;

      const user = makeUser({ id: 'user-1', email: 'alice@example.com' });
      // Disable order_confirmation but keep other categories enabled
      preferencesService.updatePreferences(user.id, {
        email: { categories: { order_confirmation: false } },
      });

      // order_confirmation should be suppressed
      await eventBus.emit(makeOrderCreatedEvent(user));
      expect(emailAdapter.getSentEmails()).toHaveLength(0);

      // order_status_update should still go through
      // Note: order:status-changed uses order.userId as recipient. With email adapter,
      // this will fail email validation unless userId is an email.
      const order = makeOrder({ userId: user.email, status: 'confirmed' });
      await eventBus.emit(makeStatusChangedEvent(order, 'pending', 'confirmed'));

      // We need preferences for the userId used in the status-changed event
      preferencesService.updatePreferences(user.email, { email: { enabled: true } });
      emailAdapter.clearSentEmails();
      notificationService.clearNotifications();

      await eventBus.emit(makeStatusChangedEvent(order, 'confirmed', 'shipped'));

      const emailNotifs = notificationService.getNotifications().filter(
        (n) => n.channel === 'email' && n.status === 'sent',
      );
      expect(emailNotifs).toHaveLength(1);
      expect(emailNotifs[0]!.type).toBe('order_status_update');
    });

    it('should not send SMS when SMS is disabled (default)', async () => {
      const { eventBus, smsAdapter, notificationService, preferencesService } = pipeline;

      const user = makeUser({ id: 'user-1', email: 'alice@example.com' });
      // Create default preferences (SMS disabled by default)
      preferencesService.getOrCreatePreferences(user.id);

      await eventBus.emit(makeOrderCreatedEvent(user));

      // SMS adapter should NOT be called (preferences suppress it)
      const smsNotifs = notificationService.getNotifications().filter((n) => n.channel === 'sms');
      expect(smsNotifs).toHaveLength(0);
    });

    it('should not send webhook when webhook is disabled (default)', async () => {
      const { eventBus, webhookAdapter, notificationService, preferencesService } = pipeline;

      const user = makeUser({ id: 'user-1', email: 'alice@example.com' });
      // Create default preferences (webhook disabled by default)
      preferencesService.getOrCreatePreferences(user.id);

      await eventBus.emit(makeOrderCreatedEvent(user));

      // Webhook adapter should NOT be called
      expect(webhookAdapter.getDeliveries()).toHaveLength(0);
      const webhookNotifs = notificationService.getNotifications().filter((n) => n.channel === 'webhook');
      expect(webhookNotifs).toHaveLength(0);
    });

    it('should send to enabled channels only in multi-channel setup', async () => {
      const { eventBus, emailAdapter, smsAdapter, webhookAdapter, notificationService, preferencesService } = pipeline;

      const user = makeUser({ id: 'user-1', email: 'alice@example.com' });
      // Enable email and webhook, keep SMS disabled
      preferencesService.updatePreferences(user.id, {
        email: { enabled: true },
        webhook: { enabled: true },
        sms: { enabled: false },
      });

      await eventBus.emit(makeOrderCreatedEvent(user));

      // Email: sent
      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      // SMS: suppressed by preferences
      const smsNotifs = notificationService.getNotifications().filter((n) => n.channel === 'sms');
      expect(smsNotifs).toHaveLength(0);
      // Webhook: sent
      expect(webhookAdapter.getDeliveries()).toHaveLength(1);
    });

    it('should respect per-user preference independence', async () => {
      const { eventBus, emailAdapter, notificationService, preferencesService } = pipeline;

      const alice = makeUser({ id: 'user-alice', email: 'alice@example.com' });
      const bob = makeUser({ id: 'user-bob', email: 'bob@example.com' });

      // Alice: email disabled
      preferencesService.updatePreferences(alice.id, { email: { enabled: false } });
      // Bob: email enabled (default)
      preferencesService.getOrCreatePreferences(bob.id);

      await eventBus.emit(makeOrderCreatedEvent(alice, makeOrder({ id: 'order-a', userId: alice.id })));
      await eventBus.emit(makeOrderCreatedEvent(bob, makeOrder({ id: 'order-b', userId: bob.id })));

      // Only Bob's email should be sent
      const sent = emailAdapter.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]!.to).toBe('bob@example.com');

      // Alice has no email notification, Bob has one
      const aliceNotifs = notificationService.getNotificationsForRecipient('alice@example.com');
      const bobNotifs = notificationService.getNotificationsForRecipient('bob@example.com');
      expect(aliceNotifs.filter((n) => n.channel === 'email')).toHaveLength(0);
      expect(bobNotifs.filter((n) => n.channel === 'email')).toHaveLength(1);
    });

    it('should send all channels when no preferences exist (email default enabled, SMS/webhook disabled)', async () => {
      const { eventBus, emailAdapter, smsAdapter, webhookAdapter, notificationService } = pipeline;

      const user = makeUser({ id: 'user-nopref', email: 'nopref@example.com' });
      // Do NOT create preferences — rely on defaults

      await eventBus.emit(makeOrderCreatedEvent(user));

      // Email: default enabled → sent
      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      // SMS: default disabled → suppressed
      const smsNotifs = notificationService.getNotifications().filter((n) => n.channel === 'sms');
      expect(smsNotifs).toHaveLength(0);
      // Webhook: default disabled → suppressed
      const webhookNotifs = notificationService.getNotifications().filter((n) => n.channel === 'webhook');
      expect(webhookNotifs).toHaveLength(0);
    });
  });

  // =========================================================================
  // 6. Notification ordering
  // =========================================================================
  describe('notification ordering', () => {
    it('should preserve FIFO order across rapid events through the full pipeline', async () => {
      const { eventBus, notificationService, preferencesService } = pipeline;

      const user = makeUser({ id: 'user-1', email: 'alice@example.com' });
      preferencesService.getOrCreatePreferences(user.id);

      // Emit multiple events rapidly without awaiting individually
      const order = makeOrder({ userId: user.id });
      const p1 = eventBus.emit(makeOrderCreatedEvent(user, order));
      const p2 = eventBus.emit(makeStatusChangedEvent(order, 'pending', 'confirmed'));
      await Promise.all([p1, p2]);

      // Email notifications should be in order
      const emailNotifs = notificationService.getNotifications().filter((n) => n.channel === 'email');
      expect(emailNotifs.length).toBeGreaterThanOrEqual(2);
      expect(emailNotifs[0]!.type).toBe('order_confirmation');
      expect(emailNotifs[1]!.type).toBe('order_status_update');
    });

    it('should maintain order across multiple channels', async () => {
      const { eventBus, notificationService, preferencesService } = pipeline;

      const user = makeUser({ id: 'user-1', email: 'alice@example.com' });
      preferencesService.updatePreferences(user.id, {
        email: { enabled: true },
        webhook: { enabled: true },
      });

      const order = makeOrder({ userId: user.id });

      await eventBus.emit(makeOrderCreatedEvent(user, order));
      await eventBus.emit(makeStatusChangedEvent(order, 'pending', 'confirmed'));

      // All notifications should maintain temporal ordering:
      // First event's channels come before second event's channels
      const allNotifs = notificationService.getNotifications();
      const confirmations = allNotifs.filter((n) => n.type === 'order_confirmation');
      const updates = allNotifs.filter((n) => n.type === 'order_status_update');

      // All order_confirmation notifications should have lower IDs than order_status_update
      const maxConfirmationId = Math.max(
        ...confirmations.map((n) => parseInt(n.id.replace('notif-', ''), 10)),
      );
      const minUpdateId = Math.min(
        ...updates.map((n) => parseInt(n.id.replace('notif-', ''), 10)),
      );
      expect(maxConfirmationId).toBeLessThan(minUpdateId);
    });
  });

  // =========================================================================
  // 7. Multi-channel delivery
  // =========================================================================
  describe('multi-channel delivery', () => {
    it('should deliver through all enabled channels for the same event', async () => {
      const { eventBus, emailAdapter, webhookAdapter, notificationService, historyService, preferencesService } = pipeline;

      const user = makeUser({ id: 'user-1', email: 'alice@example.com' });
      // Enable all supported channels
      preferencesService.updatePreferences(user.id, {
        email: { enabled: true },
        sms: { enabled: true },
        webhook: { enabled: true },
      });

      await eventBus.emit(makeOrderCreatedEvent(user));

      // Email: sent (valid email recipient)
      expect(emailAdapter.getSentEmails()).toHaveLength(1);

      // Webhook: sent (no recipient format restriction)
      expect(webhookAdapter.getDeliveries()).toHaveLength(1);

      // SMS: failed (recipient is email, not phone number — architecture limitation)
      const smsNotifs = notificationService.getNotifications().filter((n) => n.channel === 'sms');
      expect(smsNotifs).toHaveLength(1);
      expect(smsNotifs[0]!.status).toBe('failed');

      // Total notifications recorded = email(sent) + sms(failed) + webhook(sent)
      expect(notificationService.getNotificationCount()).toBe(3);

      // All are logged in history
      expect(historyService.getCount()).toBe(3);
    });

    it('should handle adapter failure without blocking other adapters', async () => {
      const { eventBus, emailAdapter, webhookAdapter, notificationService, preferencesService } = pipeline;

      const user = makeUser({ id: 'user-1', email: 'alice@example.com' });
      preferencesService.updatePreferences(user.id, {
        email: { enabled: true },
        webhook: { enabled: true },
      });

      // Make email adapter fail
      emailAdapter.setTransport(async () => false);

      await eventBus.emit(makeOrderCreatedEvent(user));

      // Email failed
      const emailNotifs = notificationService.getNotifications().filter((n) => n.channel === 'email');
      expect(emailNotifs).toHaveLength(1);
      expect(emailNotifs[0]!.status).toBe('failed');

      // Webhook still succeeded
      const webhookNotifs = notificationService.getNotifications().filter((n) => n.channel === 'webhook');
      expect(webhookNotifs).toHaveLength(1);
      expect(webhookNotifs[0]!.status).toBe('sent');
    });
  });

  // =========================================================================
  // 8. Full round-trip: event → preferences → adapter → history
  // =========================================================================
  describe('full round-trip verification', () => {
    it('should complete the full pipeline from domain event to history log', async () => {
      const { eventBus, emailAdapter, historyService, preferencesService, notificationService } = pipeline;

      // 1. Create user with preferences
      const user = makeUser({ id: 'user-1', email: 'alice@example.com' });
      preferencesService.getOrCreatePreferences(user.id);

      // 2. Emit domain event
      const order = makeOrder({ id: 'order-100', userId: user.id });
      await eventBus.emit(makeOrderCreatedEvent(user, order));

      // 3. Verify adapter delivery
      const sentEmails = emailAdapter.getSentEmails();
      expect(sentEmails).toHaveLength(1);
      expect(sentEmails[0]!.to).toBe('alice@example.com');

      // 4. Verify in-memory notification record
      const notifs = notificationService.getNotifications().filter(
        (n) => n.channel === 'email' && n.type === 'order_confirmation',
      );
      expect(notifs).toHaveLength(1);
      expect(notifs[0]!.status).toBe('sent');
      expect(notifs[0]!.metadata).toEqual(
        expect.objectContaining({ orderId: 'order-100', userId: 'user-1' }),
      );

      // 5. Verify history log persistence
      const logs = historyService.query({
        recipient: 'alice@example.com',
        type: 'order_confirmation',
        channel: 'email',
        status: 'sent',
      });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.subject).toContain('Order Confirmation');
      expect(logs[0]!.metadata).toEqual(
        expect.objectContaining({ orderId: 'order-100', userId: 'user-1' }),
      );
    });

    it('should handle the complete order lifecycle notification flow', async () => {
      const { eventBus, emailAdapter, historyService, preferencesService } = pipeline;

      const user = makeUser({ id: 'user-1', email: 'alice@example.com' });
      preferencesService.getOrCreatePreferences(user.id);

      const order = makeOrder({ id: 'order-200', userId: user.id });

      // Step 1: Order created
      await eventBus.emit(makeOrderCreatedEvent(user, order));

      // Step 2: Order confirmed (recipient = userId, which is not an email → email fails)
      await eventBus.emit(makeStatusChangedEvent(
        { ...order, status: 'confirmed' },
        'pending',
        'confirmed',
      ));

      // Step 3: Order shipped
      await eventBus.emit(makeStatusChangedEvent(
        { ...order, status: 'shipped' },
        'confirmed',
        'shipped',
      ));

      // Verify email was sent for order:created
      const sentEmails = emailAdapter.getSentEmails();
      expect(sentEmails).toHaveLength(1);
      expect(sentEmails[0]!.to).toBe('alice@example.com');

      // Verify history has entries for all events
      const allLogs = historyService.query({});
      expect(allLogs.length).toBeGreaterThanOrEqual(3);

      // Confirm there's at least one order_confirmation and order_status_update
      const confirmLogs = historyService.query({ type: 'order_confirmation' });
      const updateLogs = historyService.query({ type: 'order_status_update' });
      expect(confirmLogs.length).toBeGreaterThanOrEqual(1);
      expect(updateLogs.length).toBeGreaterThanOrEqual(1);
    });
  });
});

